def exit() -> None:
    """pgzero exposes a builtin exit() that quits the game."""
    quit_game()


# --- the mixer stand-in -----------------------------------------------------
# A no-op object matching the slice of pygame.mixer's API the games' audio
# boilerplate calls (real audio is handled by pgzero_gl.audio).  Exported as
# `mixer` so the games' init/quit/set_num_channels lines keep working with
# `pygame.mixer.` replaced by `mixer.`.


class _Mixer:
    """A no-op stand-in for ``pygame.mixer`` (audio is handled by :mod:`audio`)."""

    def quit(self) -> None:
        pass

    def init(self, *a: Any, **k: Any) -> None:
        pass

    def set_num_channels(self, *a: Any, **k: Any) -> None:
        pass

    def find_channel(self, *a: Any, **k: Any) -> None:
        return None

    def get_busy(self) -> bool:
        return False

    class Sound:  # only used as a type by some games
        def __init__(self, *a: Any, **k: Any) -> None:
            pass

        def play(self, *a: Any, **k: Any) -> None:
            pass


mixer: Any = _Mixer()
